import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"显示器分享","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/电脑/显示器.md","filePath":"ccc/电脑/显示器.md"}`),a={name:`ccc/电脑/显示器.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="显示器分享" tabindex="-1">显示器分享 <a class="header-anchor" href="#显示器分享" aria-label="Permalink to “显示器分享”">​</a></h1><p>更新于2023.3.24</p><p>一年评测一两百台显示器的显示器评测大师毅种循环所撰写的文章<a href="https://zhuanlan.zhihu.com/p/1972398086295904276" target="_blank" rel="noreferrer">《别买也别租校色仪了，它们只会让显示器更偏色！》</a>介绍了为什么追求色准反而没必要用民用级设备校色。其推荐追求色准，依赖厂家的天价专业设备与实验室是目前最切实可行的。无疑艺卓、NEC无愧于专业二字，明基应该说算是一个挑战者。据大师毅种循环介绍，零售显示器中小米、海信、华为、ROG的重点型号，LG、三星的中高端型号，厂家还是对色准有追求的。</p><ul><li><a href="http://www.xxrsm.com/" target="_blank" rel="noreferrer">小雪人数码</a>评测，他店里卖啥测啥。</li><li><a href="https://www.rtings.com/" target="_blank" rel="noreferrer">rtings</a>国外评测。</li><li><a href="https://www.panelook.cn" target="_blank" rel="noreferrer">屏库</a>可以查面板参数</li><li><a href="https://www.expreview.com/76357.html" target="_blank" rel="noreferrer">超能网的不同刷新率响应时间测试</a></li><li><a href="https://www.expreview.com/77103.html" target="_blank" rel="noreferrer">超能网的背光科普</a></li></ul><h2 id="广色域" tabindex="-1">广色域 <a class="header-anchor" href="#广色域" aria-label="Permalink to “广色域”">​</a></h2><p>windows11 已经更新ACM功能，接管色彩管理，广色域过饱和已经是历史。</p><p><a href="https://zhuanlan.zhihu.com/p/623498522" target="_blank" rel="noreferrer">详见显示器色彩管理</a></p><h2 id="点距与人体工学" tabindex="-1">点距与人体工学 <a class="header-anchor" href="#点距与人体工学" aria-label="Permalink to “点距与人体工学”">​</a></h2><p>点距既像素点间的距离。</p><p>肉眼分辨极限点距 = 眼到屏幕距离（mm） / 3438。（根据人眼可区分的最小视角1分角（1/60度）计算）</p><p>推荐屏幕宽度 = 人眼与屏幕的距离 × 1.154 - 6 （27寸16：9推荐眼离屏57cm）根据人眼平均视角计算看到整个屏幕不需要转脖子的最小距离。</p><p><a href="http://www.ab126.com/goju/2942.html" target="_blank" rel="noreferrer">PPI计算器</a>可以计算点距。</p><p><a href="https://dinex86.github.io/FOV-Calculator/" target="_blank" rel="noreferrer">FOV计算器</a></p><p>所谓IPhone4 视网膜屏的点距 0.077mm，在26cm的视距下达到人眼极限。 常见显示器视距约为70cm，该距离下人眼分辨极限点距约为0.2cm，推荐屏幕最大宽度约为74.78cm。</p><p>我自己喜欢的点距是0.27mm，该点距下，不需要dpi缩放，保持100% 文字大小就很舒服。</p><h2 id="刷新率" tabindex="-1">刷新率 <a class="header-anchor" href="#刷新率" aria-label="Permalink to “刷新率”">​</a></h2><p>  刷新率（如144hz）只和面板用的刷新模块有关，而肉眼可见的拖影只和液晶面板有本身固有的响应延迟有关。只有当液晶面板本身固有延迟很低的时候，更高刷新率才有意义。</p><h2 id="小品牌" tabindex="-1">小品牌 <a class="header-anchor" href="#小品牌" aria-label="Permalink to “小品牌”">​</a></h2><p>​ 显示器有三个部分组成：</p><ul><li>液晶模组（液晶玻璃加背光）</li><li>驱动板</li><li>模具</li></ul><p>​ 通常大部分耳熟能详的品牌比如AOC冠捷，只进行了模具生产和组装。因此购买同样使用原厂模组的小厂生产的显示器，不仅在显示效果上不会有任何区别，而且价格实惠。</p><p>​ 推荐两个品牌，在社群中有一定曝光度，同时承诺保证原厂模组+性能不妥协的驱动板。面板型号和驱动板型号向老板咨询的话会说的很清楚。即使不打算购买小品牌，也可以通过他们在售产品了解到目前最新最流行的面板是什么。</p><p>  散屏及diy显示器还有更便宜的，但是有用第三方模组（原厂液晶玻璃+比较烂的背光），还有卖测试模组的，质量参差不齐，风险较大。</p><ul><li>IC谷星 <a href="https://qihesm.tmall.com/?spm=a1z10.1-b-s.1997427721.d4918089.458573e8RtvKMv" target="_blank" rel="noreferrer">天猫柒和数码专营店</a> <a href="https://weibo.com/p/1006065879143989" target="_blank" rel="noreferrer">店主老牛微博</a> <a href="https://tr123.taobao.com/shop/view_shop.htm?spm=a230r.1.14.36.5763786eYQiDaA&amp;user_number_id=522346483" target="_blank" rel="noreferrer">坦然数码科技</a>在微博上经常批判友商的营销话术。</li><li>宏夏 <a href="https://shop278111058.taobao.com/?spm=2013.1.0.0.67197951VgzqCo" target="_blank" rel="noreferrer">宏夏淘宝店</a> 主打优化游戏延迟固件。</li></ul><p>  像京东那样能让你一两个亮点就换货是不可能的，之所以价格优惠，是他们拿的货本来<strong>亮点</strong>就多。</p><h2 id="品牌" tabindex="-1">品牌 <a class="header-anchor" href="#品牌" aria-label="Permalink to “品牌”">​</a></h2><ul><li><strong>推荐</strong>联合创新（泰坦军团），小米，明基，华为，雷神，海信，LG等品牌。</li><li>👇acer宏碁一般最便宜，aoc代工，有很多用组装模组的型号，不同批次用的模组还都不一样，非常混乱。</li><li>👇AOC冠捷收购了飞利浦等品牌，利用自建模组封装厂打价格战，不断刷新底线。</li><li>👇优派只用第三方模组打价格战，敬而远之。</li><li>👇华硕，外星人全是贴牌，卖高溢价。主打性价比的产品，全是贴牌垃圾。</li><li>👇微星非自建团队，卖一台算一台。产品线混乱不堪。</li><li>👇戴尔，傻多戴，出厂校色竟然是吹牛逼的假把式。</li></ul><h2 id="原厂模组vs第三方模组" tabindex="-1">原厂模组VS第三方模组 <a class="header-anchor" href="#原厂模组vs第三方模组" aria-label="Permalink to “原厂模组VS第三方模组”">​</a></h2><p>  社群中普遍认为原厂模组比第三方模组好，从色域和实测显示参数上确实存在差距，第三方模组普遍都是拉了跨的。我认为这同传统厂商只是代工组装厂有很大的关系，他们费劲向产业链上游发展的目的只会是降低成本，赚更多的钱。</p><p>如果采购液晶玻璃自封装更好的背光，组装模组不比原厂模组差。</p><h2 id="面板" tabindex="-1">面板 <a class="header-anchor" href="#面板" aria-label="Permalink to “面板”">​</a></h2><h3 id="ips" tabindex="-1">IPS <a class="header-anchor" href="#ips" aria-label="Permalink to “IPS”">​</a></h3><p>  不二之选，无论是设计，游戏又或是日常使用，色准，色域，可视角度，响应时间相对mva和tn都有提升，相对更新的OLED，micro led又有成本优势。</p><h3 id="mva" tabindex="-1">MVA <a class="header-anchor" href="#mva" aria-label="Permalink to “MVA”">​</a></h3><p>  MVA优点是暗部细节更好，对比度高，但是响应时间非常长。电竞屏加压之后响应时间还是很长，灰阶变烂，反而优势没了。MVA大屏电视配合棋盘控光，播放hdr资源相对IPS大屏电视有明显优势。</p><h3 id="tn" tabindex="-1">TN <a class="header-anchor" href="#tn" aria-label="Permalink to “TN”">​</a></h3><p>  FPS核心玩家必备。友达新TN色彩各方面已经比以前的tn好很多，但还是会明显泛白，可视角度有很大的改善，但和IPS比还是略逊一筹。</p><h3 id="oled" tabindex="-1">OLED <a class="header-anchor" href="#oled" aria-label="Permalink to “OLED”">​</a></h3><p>  自发光有机物，高亮度，高对比度，延迟比tn还低，缺点是成本高，有烧屏现象，目前已经在中高端笔记本当中逐渐推广，进入显示器市场指日可待。</p><h3 id="micro-led" tabindex="-1">MICRO LED <a class="header-anchor" href="#micro-led" aria-label="Permalink to “MICRO LED”">​</a></h3><p>  自发光半导体，除了有OLED的优势外，延迟更低，功耗更低，更耐高温或低温，使用寿命更长。成本暂时比OLED还高。</p><h2 id="背光" tabindex="-1">背光 <a class="header-anchor" href="#背光" aria-label="Permalink to “背光”">​</a></h2><h3 id="wled" tabindex="-1">WLED <a class="header-anchor" href="#wled" aria-label="Permalink to “WLED”">​</a></h3><p>  最普通的LED背光，在蓝光LED上覆盖荧光粉变成白光，再透过滤色镜变成红蓝绿三色光。最廉价，蓝光能量最大。一般覆盖srgb100%就顶天了，做不到广色域。</p><h3 id="ksf-led" tabindex="-1">KSF LED <a class="header-anchor" href="#ksf-led" aria-label="Permalink to “KSF LED”">​</a></h3><p>  在LED的基础上用改进型的荧光粉，Lg nano IPS采用这种背光方式。覆盖95%的DCI-P3色域。</p><h3 id="rgb-led" tabindex="-1">RGB LED <a class="header-anchor" href="#rgb-led" aria-label="Permalink to “RGB LED”">​</a></h3><p>  很少见，只会在专业显示器出现，价格非常贵，分别用三色led灯珠发出三色光。</p><h3 id="gb-r-led-rb-g-led" tabindex="-1">GB-r LED，RB-g LED <a class="header-anchor" href="#gb-r-led-rb-g-led" aria-label="Permalink to “GB-r LED，RB-g LED”">​</a></h3><p>  分别把RGB LED中的红色LED或者绿色LED替换成了红色或者绿色的荧光粉。其中GB-r相对rgb还存在红光范围过宽的缺点，RB-g从光谱上看几乎没什么缺点。一般只有对色准要求特别高的时候才会选择，比如设计用途。</p><h3 id="qled" tabindex="-1">QLED <a class="header-anchor" href="#qled" aria-label="Permalink to “QLED”">​</a></h3><p>  用量子点增强膜代替荧光粉，实现广色域的不二之选。</p><h3 id="mini-led" tabindex="-1">Mini Led <a class="header-anchor" href="#mini-led" aria-label="Permalink to “Mini Led”">​</a></h3><p>  micro led演进路线上点距微缩的还不够做显示屏，但是可以做背光，广色域，对比度高，还有精细控光。对显示器我不认为有意义。</p>`,54)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};